        """Add module permissions to a role."""
        for module_code, perm_types in module_perms.items():
            module = get_module(module_code)
            if module:
                for perm_type in perm_types:
                    ModulePermission.objects.get_or_create(
                        role=role,
                        module=module,
                        permission_type=perm_type
                    )

